insert into clinical_notes (patient_id, sort, author, dept, noted_at, segments) values
  ((select id from patients where chart_no = '00513382'), 0, '서연우 과장', '정신건강의학과', '2026-06-22 13:40', '[{"label":"S)","text":" 2주간 우울감·무기력 악화, 입면 곤란(1시간 이상), 직장 복귀 스트레스. 자살사고 간헐(빈도 증가), 구체적 계획 없음."},{"label":"O)","text":" MSE — 외모 단정, 정신운동 경도 지체, 정동 우울·불안, 사고흐름 논리적, 자살사고(+)·계획(−), 병식 양호, 인지 정상. PHQ-9 14 · GAD-7 11 · ISI 18."},{"label":"A)","text":" 주요우울장애, 재발성, 중등도(F33.1) / 범불안장애(F41.1) / 비기질성 불면증(F51.0)."},{"label":"P)","text":" 에스시탈로프람 15mg 증량, 쿠에티아핀 취침전 유지, CBT 주 1회 연계, 자살안전계획 갱신, 2주 후 재평가."}]'::jsonb),
  ((select id from patients where chart_no = '00513382'), 1, '서연우 과장', '정신건강의학과', '2026-06-08 13:20', '[{"label":"S)","text":" 수면 일부 호전, 낮 활동량 증가. 식욕 회복 중."},{"label":"A)","text":" 주요우울장애 부분 관해 경과."},{"label":"P)","text":" 약물 유지, 활동 스케줄링 과제 부여. PHQ-9 15."}]'::jsonb),
  ((select id from patients where chart_no = '00513382'), 2, '한가람 임상심리사', '심리평가', '2026-05-25 11:00', '[{"label":"평가)","text":" 종합심리검사(Full Battery) — MMPI-2, BDI-II, 로르샤흐. 우울·불안 척도 상승, 대인 위축 시사."},{"label":"권고)","text":" 인지행동치료 적응증, 자동적 사고 다루기 우선."}]'::jsonb);
